// Get transcript segments from WayinVideo
const segments = $('4. WayinVideo — Get Transcript Results').item.json.data.transcript || [];

if (segments.length === 0) {
  throw new Error('Transcript is empty — check if the video URL is valid and publicly accessible.');
}

// Format transcript — clean readable text for GPT
const formattedTranscript = segments
  .map(s => {
    const timeInSeconds = Math.floor(s.start / 1000);
    const minutes = Math.floor(timeInSeconds / 60);
    const seconds = timeInSeconds % 60;
    const timestamp = `${minutes}:${seconds.toString().padStart(2, '0')}`;
    return `[${s.speaker} | ${timestamp}] ${s.text.trim()}`;
  })
  .join('\n');

// Plain text version for caption writing
const plainText = segments.map(s => s.text.trim()).join(' ');

// Duration
const lastSegment = segments[segments.length - 1];
const totalDurationMs = lastSegment?.end || 0;
const totalMinutes = Math.round(totalDurationMs / 60000);

// Speakers
const speakers = [...new Set(segments.map(s => s.speaker))];

return [{
  json: {
    formattedTranscript,
    plainText,
    totalMinutes,
    speakerCount: speakers.length,
    videoTitle: $('1. Form — Video URL + Details').item.json['Video Title'],
    videoUrl: $('1. Form — Video URL + Details').item.json['Video URL'],
    brandName: $('1. Form — Video URL + Details').item.json['Brand / Page Name'],
    targetAudience: $('1. Form — Video URL + Details').item.json['Target Audience'],
    postTone: $('1. Form — Video URL + Details').item.json['Post Tone'],
    includeLink: $('1. Form — Video URL + Details').item.json['Include Video Link in Post?']
  }
}];

// Parse AI output — extract caption and hashtags
const output = $input.first().json.output || '';

// Extract FACEBOOK CAPTION
const captionMatch = output.match(/FACEBOOK CAPTION:\s*([\s\S]*?)(?=\nHASHTAGS:|$)/);
const caption = captionMatch ? captionMatch[1].trim() : '';

// Extract HASHTAGS
const hashtagsMatch = output.match(/HASHTAGS:\s*([\s\S]*?)(?=\nCHARACTER COUNT:|$)/);
const hashtags = hashtagsMatch ? hashtagsMatch[1].trim() : '';

// Extract CHARACTER COUNT
const charCountMatch = output.match(/CHARACTER COUNT:\s*([\d]+)/);
const charCount = charCountMatch ? parseInt(charCountMatch[1]) : caption.length;

// Build full post message — caption + hashtags
const fullMessage = `${caption}\n\n${hashtags}`.trim();

if (!caption) {
  throw new Error('Could not parse Facebook caption from AI output. Check AI prompt output format.');
}

return [{
  json: {
    caption,
    hashtags,
    fullMessage,
    charCount,
    videoTitle: $('7. Code — Format Transcript').item.json.videoTitle,
    videoUrl: $('7. Code — Format Transcript').item.json.videoUrl,
    brandName: $('7. Code — Format Transcript').item.json.brandName,
    postTone: $('7. Code — Format Transcript').item.json.postTone
  }
}];
